"""
Parameterized generator for GH232_core_123085.

Source PR:    https://github.com/home-assistant/core/pull/123085
Source Issue: https://github.com/home-assistant/core/issues/123008

Seed varies: renames 'after' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH232_core_123085'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH232_core_123085'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('after', 'after' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH232_core_123085',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'home-assistant/core',
                "pr_number": 123085,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/home-assistant/core/pull/123085",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'homeassistant/components/husqvarna_automower/coordinator.py': '"""Data UpdateCoordinator for the Husqvarna Automower integration."""\n\nimport asyncio\nfrom datetime import timedelta\nimport logging\n\nfrom aioautomower.exceptions import (\n    ApiException,\n    AuthException,\n    HusqvarnaWSServerHandshakeError,\n)\nfrom aioautomower.model import MowerAttributes\nfrom aioautomower.session import AutomowerSession\n\nfrom homeassistant.config_entries import ConfigEntry\nfrom homeassistant.core import HomeAssistant, callback\nfrom homeassistant.exceptions import ConfigEntryAuthFailed\nfrom homeassistant.helpers.update_coordinator import DataUpdateCoordinator, UpdateFailed\n\nfrom .const import DOMAIN\n\n_LOGGER = logging.getLogger(__name__)\nMAX_WS_RECONNECT_TIME = 600\nSCAN_INTERVAL = timedelta(minutes=8)\n\n\nclass AutomowerDataUpdateCoordinator(DataUpdateCoordinator[dict[str, MowerAttributes]]):\n    """Class to manage fetching Husqvarna data."""\n\n    config_entry: ConfigEntry\n\n    def __init__(\n        self, hass: HomeAssistant, api: AutomowerSession, entry: ConfigEntry\n    ) -> None:\n        """Initialize data updater."""\n        super().__init__(\n            hass,\n            _LOGGER,\n            name=DOMAIN,\n            update_interval=SCAN_INTERVAL,\n        )\n        self.api = api\n\n        self.ws_connected: bool = False\n\n    async def _async_update_data(self) -> dict[str, MowerAttributes]:\n        """Subscribe for websocket and poll data from the API."""\n        if not self.ws_connected:\n            await self.api.connect()\n            self.api.register_data_callback(self.callback)\n            self.ws_connected = True\n        try:\n            return await self.api.get_status()\n        except ApiException as err:\n            raise UpdateFailed(err) from err\n        except AuthException as err:\n            raise ConfigEntryAuthFailed(err) from err\n\n    @callback\n    def callback(self, ws_data: dict[str, MowerAttributes]) -> None:\n        """Process websocket callbacks and write them to the DataUpdateCoordinator."""\n        self.async_set_updated_data(ws_data)\n\n    async def client_listen(\n        self,\n        hass: HomeAssistant,\n        entry: ConfigEntry,\n        automower_client: AutomowerSession,\n        reconnect_time: int = 2,\n    ) -> None:\n        """Listen with the client."""\n        try:\n            await automower_client.auth.websocket_connect()\n            reconnect_time = 2\n            await automower_client.start_listening()\n        except HusqvarnaWSServerHandshakeError as err:\n            _LOGGER.debug(\n                "Failed to connect to websocket. Trying to reconnect: %s", err\n            )\n\n        if not hass.is_stopping:\n            await asyncio.sleep(reconnect_time)\n            reconnect_time = min(reconnect_time * 2, MAX_WS_RECONNECT_TIME)\n            await self.client_listen(\n                hass=hass,\n                entry=entry,\n                automower_client=automower_client,\n                reconnect_time=reconnect_time,\n            )\n',
            'tests/components/husqvarna_automower/conftest.py': '"""Test helpers for Husqvarna Automower."""\n\nfrom collections.abc import Generator\nimport time\nfrom unittest.mock import AsyncMock, patch\n\nfrom aioautomower.model import MowerAttributes\nfrom aioautomower.session import AutomowerSession, _MowerCommands\nfrom aioautomower.utils import mower_list_to_dictionary_dataclass\nfrom aiohttp import ClientWebSocketResponse\nimport pytest\n\nfrom homeassistant.components.application_credentials import (\n    ClientCredential,\n    async_import_client_credential,\n)\nfrom homeassistant.components.husqvarna_automower.const import DOMAIN\nfrom homeassistant.core import HomeAssistant\nfrom homeassistant.setup import async_setup_component\nfrom homeassistant.util import dt as dt_util\n\nfrom .const import CLIENT_ID, CLIENT_SECRET, USER_ID\n\nfrom tests.common import MockConfigEntry, load_fixture, load_json_value_fixture\n\n\n@pytest.fixture(name="jwt")\ndef load_jwt_fixture() -> str:\n    """Load Fixture data."""\n    return load_fixture("jwt", DOMAIN)\n\n\n@pytest.fixture(name="expires_at")\ndef mock_expires_at() -> float:\n    """Fixture to set the oauth token expiration time."""\n    return time.time() + 3600\n\n\n@pytest.fixture(name="scope")\ndef mock_scope() -> str:\n    """Fixture to set correct scope for the token."""\n    return "iam:read amc:api"\n\n\n@pytest.fixture(name="mower_time_zone")\nasync def mock_time_zone(hass: HomeAssistant) -> dict[str, MowerAttributes]:\n    """Fixture to set correct scope for the token."""\n    return await dt_util.async_get_time_zone("Europe/Berlin")\n\n\n@pytest.fixture(name="values")\ndef mock_values(mower_time_zone) -> dict[str, MowerAttributes]:\n    """Fixture to set correct scope for the token."""\n    return mower_list_to_dictionary_dataclass(\n        load_json_value_fixture("mower.json", DOMAIN),\n        mower_time_zone,\n    )\n\n\n@pytest.fixture\ndef mock_config_entry(jwt: str, expires_at: int, scope: str) -> MockConfigEntry:\n    """Return the default mocked config entry."""\n    return MockConfigEntry(\n        version=1,\n        domain=DOMAIN,\n        title="Husqvarna Automower of Erika Mustermann",\n        data={\n            "auth_implementation": DOMAIN,\n            "token": {\n                "access_token": jwt,\n                "scope": scope,\n                "expires_in": 86399,\n                "refresh_token": "3012bc9f-7a65-4240-b817-9154ffdcc30f",\n                "provider": "husqvarna",\n                "user_id": USER_ID,\n                "token_type": "Bearer",\n                "expires_at": expires_at,\n            },\n        },\n        unique_id=USER_ID,\n        entry_id="automower_test",\n    )\n\n\n@pytest.fixture(autouse=True)\nasync def setup_credentials(hass: HomeAssistant) -> None:\n    """Fixture to setup credentials."""\n    assert await async_setup_component(hass, "application_credentials", {})\n    await async_import_client_credential(\n        hass,\n        DOMAIN,\n        ClientCredential(\n            CLIENT_ID,\n            CLIENT_SECRET,\n        ),\n        DOMAIN,\n    )\n\n\n@pytest.fixture\ndef mock_automower_client(values) -> Generator[AsyncMock]:\n    """Mock a Husqvarna Automower client."""\n\n    mock = AsyncMock(spec=AutomowerSession)\n    mock.auth = AsyncMock(side_effect=ClientWebSocketResponse)\n    mock.commands = AsyncMock(spec_set=_MowerCommands)\n    mock.get_status.return_value = values\n\n    with patch(\n        "homeassistant.components.husqvarna_automower.AutomowerSession",\n        return_value=mock,\n    ):\n        yield mock\n',
            'tests/components/husqvarna_automower/test_init.py': '"""Tests for init module."""\n\nfrom datetime import datetime, timedelta\nimport http\nimport time\nfrom unittest.mock import AsyncMock\n\nfrom aioautomower.exceptions import (\n    ApiException,\n    AuthException,\n    HusqvarnaWSServerHandshakeError,\n)\nfrom aioautomower.model import MowerAttributes, WorkArea\nfrom freezegun.api import FrozenDateTimeFactory\nimport pytest\nfrom syrupy.assertion import SnapshotAssertion\n\nfrom homeassistant.components.husqvarna_automower.const import DOMAIN, OAUTH2_TOKEN\nfrom homeassistant.components.husqvarna_automower.coordinator import SCAN_INTERVAL\nfrom homeassistant.config_entries import ConfigEntryState\nfrom homeassistant.core import HomeAssistant\nfrom homeassistant.helpers import device_registry as dr, entity_registry as er\nfrom homeassistant.util import dt as dt_util\n\nfrom . import setup_integration\nfrom .const import TEST_MOWER_ID\n\nfrom tests.common import MockConfigEntry, async_fire_time_changed\nfrom tests.test_util.aiohttp import AiohttpClientMocker\n\nADDITIONAL_NUMBER_ENTITIES = 1\nADDITIONAL_SENSOR_ENTITIES = 2\nADDITIONAL_SWITCH_ENTITIES = 1\n\n\nasync def test_load_unload_entry(\n    hass: HomeAssistant,\n    mock_automower_client: AsyncMock,\n    mock_config_entry: MockConfigEntry,\n) -> None:\n    """Test load and unload entry."""\n    await setup_integration(hass, mock_config_entry)\n    entry = hass.config_entries.async_entries(DOMAIN)[0]\n\n    assert entry.state is ConfigEntryState.LOADED\n\n    await hass.config_entries.async_remove(entry.entry_id)\n    await hass.async_block_till_done()\n\n    assert entry.state is ConfigEntryState.NOT_LOADED\n\n\n@pytest.mark.parametrize(\n    ("scope"),\n    [\n        ("iam:read"),\n    ],\n)\nasync def test_load_missing_scope(\n    hass: HomeAssistant,\n    mock_automower_client: AsyncMock,\n    mock_config_entry: MockConfigEntry,\n) -> None:\n    """Test if the entry starts a reauth with the missing token scope."""\n    await setup_integration(hass, mock_config_entry)\n    assert mock_config_entry.state is ConfigEntryState.SETUP_ERROR\n    flows = hass.config_entries.flow.async_progress()\n    assert len(flows) == 1\n    result = flows[0]\n    assert result["step_id"] == "missing_scope"\n\n\n@pytest.mark.parametrize(\n    ("expires_at", "status", "expected_state"),\n    [\n        (\n            time.time() - 3600,\n            http.HTTPStatus.UNAUTHORIZED,\n            ConfigEntryState.SETUP_ERROR,\n        ),\n        (\n            time.time() - 3600,\n            http.HTTPStatus.INTERNAL_SERVER_ERROR,\n            ConfigEntryState.SETUP_RETRY,\n        ),\n    ],\n    ids=["unauthorized", "internal_server_error"],\n)\nasync def test_expired_token_refresh_failure(\n    hass: HomeAssistant,\n    mock_config_entry: MockConfigEntry,\n    aioclient_mock: AiohttpClientMocker,\n    status: http.HTTPStatus,\n    expected_state: ConfigEntryState,\n) -> None:\n    """Test failure while refreshing token with a transient error."""\n\n    aioclient_mock.clear_requests()\n    aioclient_mock.post(\n        OAUTH2_TOKEN,\n        status=status,\n    )\n\n    await setup_integration(hass, mock_config_entry)\n\n    assert mock_config_entry.state is expected_state\n\n\n@pytest.mark.parametrize(\n    ("exception", "entry_state"),\n    [\n        (ApiException, ConfigEntryState.SETUP_RETRY),\n        (AuthException, ConfigEntryState.SETUP_ERROR),\n    ],\n)\nasync def test_update_failed(\n    hass: HomeAssistant,\n    mock_automower_client: AsyncMock,\n    mock_config_entry: MockConfigEntry,\n    exception: Exception,\n    entry_state: ConfigEntryState,\n) -> None:\n    """Test update failed."""\n    mock_automower_client.get_status.side_effect = exception("Test error")\n    await setup_integration(hass, mock_config_entry)\n    entry = hass.config_entries.async_entries(DOMAIN)[0]\n    assert entry.state is entry_state\n\n\nasync def test_websocket_not_available(\n    hass: HomeAssistant,\n    mock_automower_client: AsyncMock,\n    mock_config_entry: MockConfigEntry,\n    caplog: pytest.LogCaptureFixture,\n    freezer: FrozenDateTimeFactory,\n) -> None:\n    """Test trying reload the websocket."""\n    mock_automower_client.start_listening.side_effect = HusqvarnaWSServerHandshakeError(\n        "Boom"\n    )\n    await setup_integration(hass, mock_config_entry)\n    assert "Failed to connect to websocket. Trying to reconnect: Boom" in caplog.text\n    assert mock_automower_client.auth.websocket_connect.call_count == 1\n    assert mock_automower_client.start_listening.call_count == 1\n    assert mock_config_entry.state is ConfigEntryState.LOADED\n    freezer.tick(timedelta(seconds=2))\n    async_fire_time_changed(hass)\n    await hass.async_block_till_done()\n    assert mock_automower_client.auth.websocket_connect.call_count == 2\n    assert mock_automower_client.start_listening.call_count == 2\n    assert mock_config_entry.state is ConfigEntryState.LOADED\n\n\nasync def test_device_info(\n    hass: HomeAssistant,\n    mock_automower_client: AsyncMock,\n    mock_config_entry: MockConfigEntry,\n    device_registry: dr.DeviceRegistry,\n    snapshot: SnapshotAssertion,\n) -> None:\n    """Test select platform."""\n\n    mock_config_entry.add_to_hass(hass)\n    await hass.config_entries.async_setup(mock_config_entry.entry_id)\n    await hass.async_block_till_done()\n    reg_device = device_registry.async_get_device(\n        identifiers={(DOMAIN, TEST_MOWER_ID)},\n    )\n    assert reg_device == snapshot\n\n\nasync def test_coordinator_automatic_registry_cleanup(\n    hass: HomeAssistant,\n    mock_automower_client: AsyncMock,\n    mock_config_entry: MockConfigEntry,\n    device_registry: dr.DeviceRegistry,\n    entity_registry: er.EntityRegistry,\n    values: dict[str, MowerAttributes],\n) -> None:\n    """Test automatic registry cleanup."""\n    await setup_integration(hass, mock_config_entry)\n    entry = hass.config_entries.async_entries(DOMAIN)[0]\n    await hass.async_block_till_done()\n\n    current_entites = len(\n        er.async_entries_for_config_entry(entity_registry, entry.entry_id)\n    )\n    current_devices = len(\n        dr.async_entries_for_config_entry(device_registry, entry.entry_id)\n    )\n\n    values.pop(TEST_MOWER_ID)\n    mock_automower_client.get_status.return_value = values\n    await hass.config_entries.async_reload(mock_config_entry.entry_id)\n    await hass.async_block_till_done()\n\n    assert (\n        len(er.async_entries_for_config_entry(entity_registry, entry.entry_id))\n        == current_entites - 37\n    )\n    assert (\n        len(dr.async_entries_for_config_entry(device_registry, entry.entry_id))\n        == current_devices - 1\n    )\n\n\nasync def test_add_and_remove_work_area(\n    hass: HomeAssistant,\n    mock_automower_client: AsyncMock,\n    mock_config_entry: MockConfigEntry,\n    freezer: FrozenDateTimeFactory,\n    entity_registry: er.EntityRegistry,\n    values: dict[str, MowerAttributes],\n) -> None:\n    """Test adding a work area in runtime."""\n    await setup_integration(hass, mock_config_entry)\n    entry = hass.config_entries.async_entries(DOMAIN)[0]\n    current_entites_start = len(\n        er.async_entries_for_config_entry(entity_registry, entry.entry_id)\n    )\n    values[TEST_MOWER_ID].work_area_names.append("new work area")\n    values[TEST_MOWER_ID].work_area_dict.update({1: "new work area"})\n    values[TEST_MOWER_ID].work_areas.update(\n        {\n            1: WorkArea(\n                name="new work area",\n                cutting_height=12,\n                enabled=True,\n                progress=12,\n                last_time_completed=datetime(\n                    2024, 10, 1, 11, 11, 0, tzinfo=dt_util.get_default_time_zone()\n                ),\n            )\n        }\n    )\n    mock_automower_client.get_status.return_value = values\n    freezer.tick(SCAN_INTERVAL)\n    async_fire_time_changed(hass)\n    await hass.async_block_till_done()\n    current_entites_after_addition = len(\n        er.async_entries_for_config_entry(entity_registry, entry.entry_id)\n    )\n    assert (\n        current_entites_after_addition\n        == current_entites_start\n        + ADDITIONAL_NUMBER_ENTITIES\n        + ADDITIONAL_SENSOR_ENTITIES\n        + ADDITIONAL_SWITCH_ENTITIES\n    )\n\n    values[TEST_MOWER_ID].work_area_names.remove("new work area")\n    del values[TEST_MOWER_ID].work_area_dict[1]\n    del values[TEST_MOWER_ID].work_areas[1]\n    values[TEST_MOWER_ID].work_area_names.remove("Front lawn")\n    del values[TEST_MOWER_ID].work_area_dict[123456]\n    del values[TEST_MOWER_ID].work_areas[123456]\n    del values[TEST_MOWER_ID].calendar.tasks[:2]\n    values[TEST_MOWER_ID].mower.work_area_id = 654321\n    mock_automower_client.get_status.return_value = values\n    freezer.tick(SCAN_INTERVAL)\n    async_fire_time_changed(hass)\n    await hass.async_block_till_done()\n    current_entites_after_deletion = len(\n        er.async_entries_for_config_entry(entity_registry, entry.entry_id)\n    )\n    assert (\n        current_entites_after_deletion\n        == current_entites_start\n        - ADDITIONAL_SWITCH_ENTITIES\n        - ADDITIONAL_NUMBER_ENTITIES\n        - ADDITIONAL_SENSOR_ENTITIES\n    )\n',
        }
